import jsonimport base64from pathlib import Pathfrom typing import Dict, Anyfrom pydantic import ValidationErrorfrom dotenv import load_dotenvfrom openai import OpenAIfrom pypdf import PdfReaderfrom pdf2image import convert_from_pathfrom PIL import Imagefrom invoice_agent.schemas import InvoiceDataload_dotenv()client = OpenAI()def extract_invoice_data(email_path: str, pdf_path: str) -> Dict[str, Any]:    """    Extract structured invoice data from:    - Email JSON file    - PDF text content    - PDF page images    """    # Step 1: Load email content    email_content = _load_email(email_path)    # Step 2: Extract PDF text    pdf_text = _extract_pdf_text(pdf_path)    # Step 3: Extract PDF page images (base64 encoded)    pdf_images = _extract_pdf_images(pdf_path)    # Step 4: Call LLM for structured extraction    structured_data = _call_extraction_model(        email_content=email_content,        pdf_text=pdf_text,        pdf_images=pdf_images,    )    # Step 5: Validate against schema    try:        invoice = InvoiceData(**structured_data)        return invoice.model_dump()    except ValidationError as e:        raise ValueError(f"Structured output validation failed: {e}")                        def _load_email(email_path: str) -> Dict[str, Any]:    """    Load email JSON file.    Expected to contain fields like subject, sender, body, attachments, etc.    """    path = Path(email_path)    if not path.exists():        raise FileNotFoundError(f"Email file not found: {email_path}")    try:        with open(path, "r", encoding="utf-8") as f:            email_data = json.load(f)    except json.JSONDecodeError:        raise ValueError("Email file is not valid JSON.")    return email_datadef _extract_pdf_text(pdf_path: str) -> str:    """    Extract raw text from all pages of a PDF.    """    path = Path(pdf_path)    if not path.exists():        raise FileNotFoundError(f"PDF file not found: {pdf_path}")    try:        reader = PdfReader(str(path))    except Exception as e:        raise ValueError(f"Failed to read PDF: {e}")    full_text = []    for page in reader.pages:        text = page.extract_text()        if text:            full_text.append(text)    return "\n".join(full_text)def _extract_pdf_images(pdf_path: str) -> list:    """    Convert each PDF page into a base64-encoded image.    We only encode the first 2 pages to control token usage.    """    path = Path(pdf_path)    if not path.exists():        raise FileNotFoundError(f"PDF file not found: {pdf_path}")    try:        pages = convert_from_path(str(path), dpi=150)    except Exception as e:        raise ValueError(f"Failed to render PDF pages: {e}")    encoded_images = []    # Limit to first 2 pages for token control    for page in pages[:2]:        buffer = Path("temp_image.jpg")        page.save(buffer, format="JPEG")        with open(buffer, "rb") as img_file:            encoded = base64.b64encode(img_file.read()).decode("utf-8")            encoded_images.append(encoded)        buffer.unlink()  # delete temp file    return encoded_imagesdef _call_extraction_model(    email_content: Dict[str, Any],    pdf_text: str,    pdf_images: list,) -> Dict[str, Any]:    """    Call GPT model to extract structured invoice data.    """    # Limit PDF text to avoid excessive token usage    truncated_pdf_text = pdf_text[:15000]    system_prompt = """You are an invoice extraction system.Extract structured invoice data from:- Email content- PDF text- PDF imagesReturn ONLY valid JSON matching this structure:{  "vendor_name": string | null,  "invoice_number": string | null,  "invoice_date": string | null,  "due_date": string | null,  "payment_terms": string | null,  "currency": string | null,  "customer_po_number": string | null,  "subtotal": number | null,  "taxes": { string: number } | null,  "total_due": number | null,  "ship_to_locations": [    {      "site_name": string | null,      "address": string | null,      "receiving_hours": string | null,      "delivery_window": string | null    }  ],  "notes": string | null,  "line_items": [    {      "sku": string | null,      "description": string | null,      "quantity": number | null,      "unit_price": number | null,      "line_total": number | null    }  ]}Rules:- Do NOT hallucinate.- If a field is missing, return null.- Extract invoice_number even if only visible in image.- Return valid JSON only. No explanations."""    user_content = f"""EMAIL CONTENT:{json.dumps(email_content, indent=2)}PDF TEXT:{truncated_pdf_text}"""    messages = [        {"role": "system", "content": system_prompt},        {"role": "user", "content": user_content},    ]    # Add images    for image_base64 in pdf_images:        messages.append({            "role": "user",            "content": [                {                    "type": "image_url",                    "image_url": {                        "url": f"data:image/jpeg;base64,{image_base64}"                    }                }            ],        })    response = client.chat.completions.create(        model="gpt-5-mini",        messages=messages,    )    raw_output = response.choices[0].message.content.strip()        # Remove markdown fences if present    if raw_output.startswith("```"):        raw_output = raw_output.split("```")[1].strip()        try:        structured_data = json.loads(raw_output)    except json.JSONDecodeError:        raise ValueError("Model did not return valid JSON.")        return structured_data